#include <iostream>
#include <string>

// TODO: Define struct Book with fields:
//   std::string title, author;
//   int pages;
// Then implement three constructors using delegation:
//   Book(const std::string& title, const std::string& author, int pages) -- initializes all members
//   Book(const std::string& title, const std::string& author)            -- delegates, pages = 300
