#include <iostream>
#include <string>

struct Book
{
    std::string title;
    std::string author;
    int pages;

    Book(const std::string& title, const std::string& author, int pages)
        : title{ title }, author{ author }, pages{ pages }
    {}

    Book(const std::string& title, const std::string& author)
        : Book{ title, author, 300 }
    {}

    explicit Book(const std::string& title)
        : Book{ title, "Unknown" }
    {}
};

int main()
{
    std::string title, author;
    int pages;
    std::cin >> title >> author >> pages;

    Book b1{ title, author, pages };
    Book b2{ title, author };
    Book b3{ title };

    std::cout << b1.title << " by " << b1.author << ", " << b1.pages << " pages\n";
    std::cout << b2.title << " by " << b2.author << ", " << b2.pages << " pages\n";
    std::cout << b3.title << " by " << b3.author << ", " << b3.pages << " pages\n";

    return 0;
}

