// Implement four constructors using a delegation chain:
//   Sensor(const std::string& name, double temperature, int count) -- initializes all members
//   Sensor(const std::string& name, double temperature)            -- delegates, count = 1
//   explicit Sensor(const std::string& name)                       -- delegates, temperature = 0.0
//   Sensor()                                                       -- delegates, name = "default"
//
// Implement:
//   void report() const
//     prints: Sensor <name>: <temperature>C (<count> sample(s))
//     temperature must use exactly 1 decimal place

int main()
{
    std::string name;
    double temperature;
    int count;
    std::cin >> name >> temperature >> count;

    Sensor s1{ name, temperature, count };
    Sensor s2{ name, temperature };
    Sensor s3{ name };
    Sensor s4{};

    s1.report();
    s2.report();
    s3.report();
    s4.report();

    return 0;
}

exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <string>

struct Sensor
{
    std::string name;
    double temperature;
    int count;

    Sensor(const std::string& name, double temperature, int count)
        : name{ name }, temperature{ temperature }, count{ count }
    {}

    Sensor(const std::string& name, double temperature)
        : Sensor{ name, temperature, 1 }
    {}

    explicit Sensor(const std::string& name)
        : Sensor{ name, 0.0 }
    {}

    Sensor()
        : Sensor{ "default" }
    {}

    void report() const
    {
        std::cout << std::fixed << std::setprecision(1);
        std::cout << "Sensor " << name << ": " << temperature << "C ("
                  << count << " sample(s))\n";
    }
};

int main()
{
    std::string name;
    double temperature;
    int count;
    std::cin >> name >> temperature >> count;

    Sensor s1{ name, temperature, count };
    Sensor s2{ name, temperature };
    Sensor s3{ name };
    Sensor s4{};

    s1.report();
    s2.report();
    s3.report();
    s4.report();

    return 0;
}
